@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500&display=swap');

@keyframes fall-fade {
  0% { transform: translateY(-30px); opacity: 0; filter: blur(5px) brightness(0.8); }
  50% { filter: blur(2px) brightness(1); }
  100% { transform: translateY(0); opacity: 1; filter: blur(0) brightness(1); }
}

@keyframes frost-glow {
  0% { box-shadow: 0 0 20px rgba(120,180,255,0.1); }
  50% { box-shadow: 0 0 45px rgba(140,200,255,0.25); }
  100% { box-shadow: 0 0 20px rgba(120,180,255,0.1); }
}

@keyframes frost-shiver {
  0%, 100% { transform: translateY(0); filter: brightness(1); }
  50% { transform: translateY(-1px); filter: brightness(1.1); }
}

.right-rail-wrapper, .page__main {
  background-image: radial-gradient(circle, rgba(120,180,255,0.05) 1px, transparent 1px);
  background-size: 22px 22px;
  background-repeat: repeat;
}

a, .page-counter {
  font-family: 'IBM Plex Mono', monospace;
  text-decoration: none;
  position: relative;
  color: rgba(210,235,255,0.85);
  transition: color 0.4s ease, transform 0.4s ease;
}

a::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -2px;
  width: 100%;
  height: 1.5px;
  background: linear-gradient(90deg, rgba(140,200,255,0.6), rgba(255,255,255,0.8), rgba(140,200,255,0.6));
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 0.4s ease, opacity 0.4s ease;
  opacity: 0.5;
}

a:hover {
  color: rgba(240,250,255,1);
  animation: frost-shiver 0.6s ease-in-out;
}

a:hover::after {
  transform: scaleX(1);
  opacity: 0.9;
}

.fandom-community-header {
  animation: fall-fade 1.8s ease forwards;
  margin: 0 auto;
  top: 3rem;
  position: relative;
  width: 95%;
  background: var(--theme-page-background-color);
  padding: 0 20px 20px 20px;
  border: 1.5px solid rgba(140,200,255,0.4);
  border-radius: 8px 8px 0 0;
  box-shadow: 0 0 25px rgba(100,150,200,0.2);
  z-index: 2;
  backdrop-filter: blur(16px);
}

.fandom-community-header__image img { opacity: 0; }

.fandom-community-header__image:before {
  content: "";
  background: url(https://static.wikia.nocookie.net/backrooms/images/8/84/Dwda.png/revision/latest/scale-to-width-down/180?cb=20251025203242&format=original) no-repeat;
  margin: 0.9rem 0 0 0;
  width: 120px;
  height: 120px;
  background-size: 100px;
  position: absolute;
  filter: brightness(0.7) contrast(1.2);
}

.page {
  animation: fall-fade 2s ease forwards, frost-glow 10s infinite ease-in-out;
  font-family: 'IBM Plex Mono', monospace;
  width: 95%;
  margin: 5rem auto 7rem auto;
  position: relative;
  border: 1.5px solid rgba(140,200,255,0.4);
  border-radius: 8px;
  background-color: rgba(3,8,15,0.75);
  box-shadow: 0 0 30px rgba(90,140,190,0.2);
  color: rgba(230,240,255,0.96);
  padding: 18px;
  text-shadow: 0 0 4px rgba(150,190,255,0.2);
  z-index: 1;
  backdrop-filter: blur(20px);
}

.theme-fandomdesktop-dark {
  --theme-accent-color: rgb(70,110,180);
  --theme-accent-label-color: #ffffff;
  --theme-body-background-color: rgb(0,8,15);
  --theme-body-background-image: url(https://static.wikia.nocookie.net/backrooms/images/3/32/Wcvsa.png/revision/latest/scale-to-width-down/180?cb=20251025200210&format=original);
  --theme-body-text-color: #dfe9ff;
  --theme-border-color: rgba(90,130,180,0.4);
  --theme-community-header-color: rgba(180,220,255,0.85);
  --theme-page-accent-mix-color: rgb(0,30,70);
  --theme-page-background-color: rgba(3,10,20,0.6);
  --theme-page-background-color--secondary: rgba(3,10,25,0.45);
  --theme-link-color: rgba(180,220,255,0.85);
  --theme-link-color--hover: #c9edff;
  --theme-sticky-nav-background-color: rgba(3,10,20,0.6);
  --theme-sticky-nav-text-color: rgba(225,235,255,0.9);
  --theme-sticky-nav-text-color--hover: #ffffff;
  --theme-page-text-color: rgba(230,240,255,0.97);
}

.sticky-modules-wrapper {
  color: rgba(230,240,255,0.9);
  border-left: 1px solid rgba(140,200,255,0.4);
  padding-left: 1rem;
}

h1, h2, h3, h4, h5, h6 {
  font-family: 'IBM Plex Mono', monospace;
  color: rgba(230,240,255,0.96);
  text-shadow: 0 0 6px rgba(120,180,255,0.2);
  letter-spacing: 0.6px;
}

.theme-fandomdesktop-dark .page-side-tool {
  border: solid 1.5px rgba(140,200,255,0.3);
  box-shadow: 0 0 25px rgba(100,150,200,0.15);
  border-radius: 12px;
  background: rgba(10,20,35,0.35);
  backdrop-filter: blur(16px);
  transition: all 0.3s ease;
}

.theme-fandomdesktop-dark .page-side-tool:hover {
  background: rgba(30,50,80,0.4);
  border-color: rgba(150,200,255,0.5);
  box-shadow: 0 0 35px rgba(150,220,255,0.3);
  transform: scale(1.05);
}


